const body = $input.first().json.body || $input.first().json;
const userMessage = body.message ?? body.user_message ?? body.text ?? '';
if (!userMessage || !String(userMessage).trim()) {
  return [{ json: { error: 'Missing message, user_message, or text in request body.', _skipRag: true } }];
}
return [{
  json: {
    user_message: String(userMessage).trim(),
    domain: 'company_policy_rollout'
  }
}];

const item = $input.first().json;
if (item._skipRag) {
  return [{ json: { success: false, error: item.error, answer: null, sources: [] } }];
}
const docs = item.documents || item.results || item.matches || [];
const context = Array.isArray(docs)
  ? docs.map((d, i) => {
      const content = typeof d === 'string' ? d : (d.pageContent || d.content || d.text || '');
      const meta = typeof d === 'object' && d.metadata ? d.metadata : {};
      const source = meta.source_file_name || meta.source || `Chunk ${i + 1}`;
      return `[Source: ${source}]\n${content}`;
    }).join('\n\n---\n\n')
  : '';
const userMessage = item.user_message || $('Build payload').first().json.user_message;
return [{
  json: {
    context: context || '(No relevant policy documents found.)',
    user_message: userMessage,
    has_context: context.length > 0
  }
}];

