const item = $input.first().json;
const choice = item.message?.content ?? item.choices?.[0]?.message?.content ?? item.content ?? item.answer ?? '';
const prev = $('Format context').first().json;
const sources = [];
if (prev.context && prev.context !== '(No relevant policy documents found.)') {
  const matches = prev.context.matchAll(/\[Source: ([^\]]+)\]/g);
  for (const m of matches) {
    if (m[1] && !sources.includes(m[1])) sources.push(m[1]);
  }
}
return [{
  json: {
    success: true,
    answer: typeof choice === 'string' ? choice : JSON.stringify(choice),
    sources: sources.length ? sources : (prev.has_context ? ['Policy documents'] : [])
  }
}];
